	base, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", fmt.Errorf("cannot parse base redirect URL: %w", err)
	}

	var redirectURL string
	if strings.HasPrefix(redirectPath, "http") {
		// If a full URL is provided, use it directly.
		redirectURL = redirectPath
	} else {
		// Ensure the custom path starts with a slash.
		if !strings.HasPrefix(redirectPath, "/") {
			redirectPath = "/" + redirectPath
		}
		// Replace the path component of the base URL.
		base.Path = redirectPath
		redirectURL = base.String()
	}

	// Validate that the resulting redirect URL is absolute.
	if _, err := url.Parse(redirectURL); err != nil {
		return "", fmt.Errorf("invalid redirect URL: %w", err)
	}

	// Generate a cryptographically random state value.
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}
	state := base64.URLEncoding.EncodeToString(b)

	// Store the state in the session cookie if provided.
	if session != nil {
		session.Name = "oauth_state"
		session.Value = state
		session.HttpOnly = true
		session.Secure = true
		session.SameSite = http.SameSiteLaxMode
		session.Path = "/"
		http.SetCookie(w, session)
	} else {
		// Fallback: use a dedicated cookie.
		http.SetCookie(w, &http.Cookie{
			Name:     "oauth_state",
			Value:    state,
			HttpOnly: true,
			Secure:   true,
			SameSite: http.SameSiteLaxMode,
			Path:     "/",
		})
	}

