// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a random state using cryptographically secure random bytes
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", errors.New("failed to generate random state: " + err.Error())
	}
	state := base64.URLEncoding.EncodeToString(b)

	// Validate and resolve the redirect URL
	finalRedirect, err := resolveRedirectURL(redirectPath)
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = finalRedirect

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation.
	// If a session cookie was provided, we update its value with the state
	// and ensure secure attributes.
	if session != nil {
		session.Name = "oauth_state"
		session.Value = state
		session.HttpOnly = true
		session.Secure = true
		session.SameSite = http.SameSiteLaxMode
		session.Path = "/"
		http.SetCookie(w, session)
	} else {
		// Fallback: use a separate cookie if no session cookie is supplied
		http.SetCookie(w, &http.Cookie{
			Name:     "oauth_state",
			Value:    state,
			HttpOnly: true,
			Secure:   true,
			SameSite: http.SameSiteLaxMode,
			Path:     "/",
		})
	}

	return authURL, nil
}

// resolveRedirectURL ensures the provided redirect path is safe to use.
// It accepts either an absolute HTTPS URL or a relative path.
// If a relative path is given, it is resolved against the base redirect URL
// defined in OAuthConfig. The final URL must use HTTPS and must belong to the
// allowed host (the host part of the original RedirectURL).
func resolveRedirectURL(redirectPath string) (string, error) {
	if redirectPath == "" {
		return "", errors.New("redirect path cannot be empty")
	}

	base, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", errors.New("invalid base redirect URL")
	}

	var u *url.URL
	if strings.HasPrefix(redirectPath, "http://") || strings.HasPrefix(redirectPath, "https://") {
		// Absolute URL provided
		u, err = url.Parse(redirectPath)
		if err != nil {
			return "", errors.New("invalid redirect URL")
		}
	} else {
		// Relative path – resolve against base
		u, err = url.Parse(redirectPath)
		if err != nil {
			return "", errors.New("invalid redirect path")
		}
		u = base.ResolveReference(u)
	}

	// Enforce HTTPS
	if u.Scheme != "https" {
		return "", errors.New("redirect URL must use HTTPS")
	}

	// Ensure host matches the allowed host (prevent open redirect)
	if u.Host != "" && u.Host != base.Host {
		return "", errors.New("redirect host is not allowed")
	}

	return u.String(), nil
}

