package main

import (
	"crypto/rand"
	"encoding/hex"
	"errors"
	"net/http"
	"net/url"
	"strings"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
// The session cookie can be used to store arbitrary session data; it is not modified by this function.
// The function writes a cookie with the OAuth state for later validation.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate that redirectPath is not empty.
	if redirectPath == "" {
		return "", errors.New("redirect path cannot be empty")
	}

	var redirectURL string

	// If redirectPath is already an absolute URL, use it as-is.
	if strings.HasPrefix(redirectPath, "http://") || strings.HasPrefix(redirectPath, "https://") {
		redirectURL = redirectPath
	} else {
		// Build an absolute URL from the request's host and scheme.
		scheme := "https"
		if r.TLS == nil {
			scheme = "http"
		}
		// Ensure the path starts with a slash.
		if !strings.HasPrefix(redirectPath, "/") {
			redirectPath = "/" + redirectPath
		}
		redirectURL = scheme + "://" + r.Host + redirectPath
	}

	// Validate the constructed redirect URL.
	if _, err := url.Parse(redirectURL); err != nil {
		return "", errors.New("invalid redirect URL")
	}

	// Create a copy of the global OAuth config so we can safely modify the redirect URL.
	config := *OAuthConfig
	config.RedirectURL = redirectURL

	// Generate a cryptographically secure state string.
	state, err := generateSecureState()
	if err != nil {
		return "", errors.New("failed to generate state")
	}

	// Build the authorization URL with the state.
	authURL := config.AuthCodeURL(state)

	// Set the state in an HttpOnly, Secure cookie for later validation.
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	// The session cookie parameter is not used directly in this implementation.
	// It can be utilized by the caller to persist additional session data.
	_ = session // avoid unused parameter warning

	return authURL, nil
}

// generateSecureState creates a random state string for the OAuth2 state parameter.
func generateSecureState() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

