// It returns the authorization URL and an error if the redirect URL is invalid or state generation fails.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Handle relative URLs by constructing a full URL from the request
	var callbackURL *url.URL
	var err error

	parsed, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect URL: " + err.Error())
	}

	// If it's a relative path, construct the full URL
	if !parsed.IsAbs() {
