		// Allow HTTP for localhost
		if isLocalhost(r.Host) {
			scheme = "http"
		}
		callbackURL, err = url.Parse(fmt.Sprintf("%s://%s%s", scheme, r.Host, redirectPath))
		if err != nil {
			return "", errors.New("invalid redirect URL: " + err.Error())
		}
	} else {
		callbackURL = parsed
	}

	// Validate the provided callback URL
	if callbackURL.Scheme == "" || callbackURL.Host == "" {
		return "", errors.New("redirect URL must be an absolute URL with scheme and host")
	}
	// Enforce HTTPS (allow HTTP for localhost)
	if callbackURL.Scheme != "https" && !isLocalhost(callbackURL.Host) {
		return "", errors.New("redirect URL must use HTTPS (or HTTP for localhost)")
	}

	// Ensure the callback URL is on an allowed host (same domain as the pre‑registered RedirectURL)
	baseRedirect, err := url.Parse(OAuthConfig.RedirectURL)
