// session is an optional cookie that will be sent back to the client.
// w is used to set cookies (state and session) and r contains request details.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Ensure redirectPath starts with a slash.
	if len(redirectPath) == 0 || redirectPath[0] != '/' {
		redirectPath = "/" + redirectPath
	}

	// Determine the request scheme (http or https).
	scheme := "http"
	if r.TLS != nil {
		scheme = "https"
	}

	// Use the Host from the request; fall back to a default if empty.
	host := r.Host
	if host == "" {
		host = "localhost"
	}

	// Build the final redirect URL.
	redirectURL := fmt.Sprintf("%s://%s%s", scheme, host, redirectPath)

	// Create a copy of the global config so we can safely override the redirect URL.
	cfg := *OAuthConfig
	cfg.RedirectURL = redirectURL

	// Generate a random state string for CSRF protection.
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("failed to generate random state: %w", err)
	}
	state := hex.EncodeToString(b)

	// Set a cookie that will carry the state to the callback endpoint.
	stateCookie := &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		Path:     "/",
		HttpOnly: true,
		Secure:   scheme == "https",
	}
