package main

import (
	"crypto/rand"
	"encoding/base64"
	"errors"
	"net/http"
	"net/url"
	"strings"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL creates an OAuth2 authorization URL for the user to authenticate.
// It validates the provided callback URL (redirectPath), generates a random state,
// and stores that state in a cookie so it can be validated later when the provider
// redirects back. The session cookie is optionally updated with the state value.
// The function returns the authorization URL or an error if the redirect URL is
// invalid or the state cannot be generated.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Use the default redirect URL as the base for constructing absolute URLs.
	baseRedirectURL := OAuthConfig.RedirectURL

	// If no redirect path is provided, use the default.
	if redirectPath == "" {
		redirectPath = baseRedirectURL
	}

	// Try to parse the redirect path as a URL.
	parsedRedirect, err := url.Parse(redirectPath)
	if err != nil {
		return "", errors.New("invalid redirect URL: must be absolute")
	}

	// If the redirect path is a relative path, combine it with the base URL.
	if parsedRedirect.Scheme == "" || parsedRedirect.Host == "" {
		// Parse the base URL to get the scheme and host.
		parsedBase, err := url.Parse(baseRedirectURL)
		if err != nil {
			return "", errors.New("invalid redirect URL: must be absolute")
		}

		// Combine the base URL with the relative path.
		// Use the path from the redirect path, preserving any query string.
		if parsedRedirect.Path != "" {
			parsedBase.Path = parsedRedirect.Path
		}
		if parsedRedirect.RawQuery != "" {
			parsedBase.RawQuery = parsedRedirect.RawQuery
		}

		redirectPath = parsedBase.String()
	}

	// Validate that redirectPath is a well‑formed absolute URL.
	parsedURL, err := url.Parse(redirectPath)
	if err != nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		return "", errors.New("invalid redirect URL: must be absolute")
	}
	// Enforce HTTPS unless the URL is a localhost address (useful for development).
	if !strings.HasPrefix(redirectPath, "https://") && !strings.HasPrefix(redirectPath, "http://localhost") {
		return "", errors.New("redirect URL must use HTTPS (or be localhost)")
	}

	// Generate a cryptographically random state string.
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", errors.New("failed to generate state")
	}
	state := base64.URLEncoding.EncodeToString(b)

	// Make a shallow copy of the global config so we can safely modify the redirect URL.
	cfg := *OAuthConfig
	cfg.RedirectURL = redirectPath

	// Build the authorization URL.
	authURL := cfg.AuthCodeURL(state)

	// Persist the state in a cookie.
	if session != nil {
		// Reuse the provided session cookie but set its value to the state.
		session.Value = state
		http.SetCookie(w, session)
	} else {
		// Default cookie name and attributes.
		http.SetCookie(w, &http.Cookie{
			Name:     "oauth_state",
			Value:    state,
			HttpOnly: true,
			Secure:   true,
			SameSite: http.SameSiteLaxMode,
			Path:     "/",
		})
	}

	return authURL, nil
}

